#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=3e3+10,INF=0x3f3f3f3f;
int dp[N][N],s[N],j;
inline double Cnt(int a,int b){return 1.0*(dp[a][j-1]+s[a]*s[a]-dp[b][j-1]-s[b]*s[b])/(s[a]-s[b]);}
int deq[N],H,T;
int main()
{
	int n=read(),m=read();rep(1,n,i)s[i]=s[i-1]+read();
	memset(dp,0x3f,sizeof(dp));rep(0,n,i)dp[i][0]=s[i]*s[i];
	for(j=1;j<m;++j)
	{
		deq[H=T=1]=0;rep(1,n,i)
		{
			while(H<T&&Cnt(deq[H],deq[H+1])<2*s[i])H++;int k=deq[H];
			dp[i][j]=dp[k][j-1]+(s[i]-s[k])*(s[i]-s[k]);
			while(H<T&&Cnt(deq[T],i)<Cnt(deq[T],deq[T-1]))T--;deq[++T]=i;
		}
	}
	printf("%d\n",dp[n][m-1]*m-s[n]*s[n]);
}
